export const TAVERN_MAP_ICON_LICENSE = {
    name: 'CC BY 3.0',
    url: 'https://creativecommons.org/licenses/by/3.0/',
    source: 'https://game-icons.net',
    attribution: 'Icons made by Delapouite and Lorc. Available on https://game-icons.net',
} as const;
export const TAVERN_MAP_ICON_ATTRIBUTION = TAVERN_MAP_ICON_LICENSE.attribution;
export const TAVERN_MAP_GAME_ICON_SIZE = 24;
export const TAVERN_MAP_LEGACY_ICON_SIZE = 20;

export const TAVERN_ATLAS_SCALE_GLYPHS: Record<TavernAtlasLocationScale, TavernGameMapIconName> = {
    city: 'castle',
    district: 'village',
    building: 'house',
    floor: 'stairs',
    room: 'door',
    outdoor: 'forest',
};

const GAME_ICON_NAME_SET = new Set<string>(TAVERN_GAME_MAP_ICON_NAMES);
const LEGACY_ICON_NAME_SET = new Set<string>(TAVERN_LEGACY_MAP_ICON_NAMES);

export function getTavernGameIconGlyph(icon: TavernMapIconName | string | undefined): TavernGameIconGlyph | null {
    const key = String(icon || '').trim();
    return GAME_ICON_NAME_SET.has(key) ? TAVERN_GAME_ICON_GLYPHS[key as TavernGameMapIconName] || null : null;
}

export function isTavernLegacyMapIcon(icon: TavernMapIconName | string | undefined): icon is TavernLegacyMapIconName {
    return LEGACY_ICON_NAME_SET.has(String(icon || '').trim());
}

export function getTavernMapIconRenderSize(icon: TavernMapIconName | string | undefined): number {
    return getTavernGameIconGlyph(icon) ? TAVERN_MAP_GAME_ICON_SIZE : TAVERN_MAP_LEGACY_ICON_SIZE;
}

export function gameIconTranslateTransform(x: number, y: number): string {
    return `translate(${Number(x.toFixed(2))}, ${Number(y.toFixed(2))})`;
}

export function gameIconScaleTransform(size = TAVERN_MAP_GAME_ICON_SIZE): string {
    return `scale(${Number((size / 512).toFixed(5))})`;
}

export function gameIconTransform(x: number, y: number, size = TAVERN_MAP_GAME_ICON_SIZE): string {
    const scale = size / 512;
    const left = Number((x - size / 2).toFixed(2));
    const top = Number((y - size / 2).toFixed(2));
    return `matrix(${Number(scale.toFixed(5))}, 0, 0, ${Number(scale.toFixed(5))}, ${left}, ${top})`;
}

export function atlasGlyphForScale(scale: TavernAtlasLocationScale | string | undefined): TavernGameMapIconName {
    const key = String(scale || '').trim() as TavernAtlasLocationScale;
    return TAVERN_ATLAS_SCALE_GLYPHS[key] || 'house';
}
